style:
.svc-hub {
  font-family: "Space Grotesk", "Inter", sans-serif;
  color: #1b1b1b;
}

.svc-hero {
  background: linear-gradient(135deg, #6b7eea, #6a4dbb);
  border-radius: 20px;
  padding: 24px 28px;
  color: #fff;
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 20px;
  box-shadow: 0 12px 30px rgba(48, 35, 78, 0.25);
}

.svc-hero-icon {
  width: 56px;
  height: 56px;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.2);
  display: grid;
  place-items: center;
  font-size: 28px;
}

.svc-hero-text h2 {
  margin: 0;
  font-size: 24px;
  font-weight: 600;
}

.svc-hero-text p {
  margin: 4px 0 0 0;
  opacity: 0.9;
  font-size: 13px;
}

.svc-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 16px;
}

.svc-tile {
  background: #fff;
  border-radius: 16px;
  padding: 16px;
  display: flex;
  gap: 12px;
  align-items: center;
  text-decoration: none;
  color: inherit;
  box-shadow: 0 8px 18px rgba(17, 24, 39, 0.08);
  border: 1px solid #eef0f4;
  transition: transform 0.18s ease, box-shadow 0.18s ease;
}

.svc-tile:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 24px rgba(17, 24, 39, 0.12);
}

.svc-tile-icon {
  width: 48px;
  height: 48px;
  border-radius: 14px;
  display: grid;
  place-items: center;
  font-size: 22px;
  background: #f3f4ff;
}

.svc-tile-master .svc-tile-icon {
  background: #eef6ff;
}

.svc-tile-report .svc-tile-icon {
  background: #f5ecff;
}

.svc-tile-body h4 {
  margin: 0;
  font-size: 15px;
  font-weight: 600;
}

.svc-tile-body p {
  margin: 4px 0 0 0;
  font-size: 12px;
  color: #6b6b6b;
}
